6	//! Embedded device artifact bundles.
7	//!
8	//! The wire format is intentionally independent of a particular accelerator
9	//! backend. A bundle names a producer, records the device target it was built
10	//! for, and carries one or more generated device-code payloads.
11	
12	use core::fmt;
13	
14	pub const ARTIFACT_SECTION_NAME: &str = ".oxart";
15	#[cfg(feature = "object-write")]
16	const ARTIFACT_ANCHOR_SECTION_NAME: &str = ".oxlink";
17	pub const ARTIFACT_MAGIC: [u8; 8] = *b"OXIDEART";
18	pub const ARTIFACT_VERSION: u16 = 2;
19	const LEGACY_ARTIFACT_VERSION: u16 = 1;
20	
21	const HEADER_BYTES: usize = 32;
22	const PAYLOAD_RECORD_BYTES: usize = 24;
23	const ENTRY_RECORD_BYTES: usize = 24;
24	
25	const OPTION_NO_FMA_CONTRACTION: u64 = 1 << 0;
26	const KNOWN_COMPILE_OPTIONS: u64 = OPTION_NO_FMA_CONTRACTION;
27	
28	/// Marker written on the second line of a versioned NVVM/LTOIR `.target`
29	/// sidecar. Its presence makes older one-line readers reject the artifact
30	/// instead of silently ignoring required compile policy.
31	pub const COMPILE_OPTIONS_TARGET_MARKER: &str = "compile-options=v1";
32	
33	const COMPILE_OPTIONS_SIDECAR_HEADER: &str = "cuda-oxide-compile-options-v1";
34	const COMPILE_OPTIONS_FMA_ON: &str = "cuda-oxide-compile-options-v1\nfma-contraction=on\n";
35	const COMPILE_OPTIONS_FMA_OFF: &str = "cuda-oxide-compile-options-v1\nfma-contraction=off\n";
36	
37	/// Compilation policy that must remain attached to a device artifact until
38	/// its final machine-code generation step.
39	///
40	/// A zero value preserves the historical defaults, which keeps version-1
41	/// bundles emitted before this field was used fully compatible.
42	#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash)]
43	pub struct ArtifactCompileOptions(u64);
44	
45	impl ArtifactCompileOptions {
46	    /// Construct the historical default policy.
47	    pub const fn new() -> Self {
48	        Self(0)
49	    }
50	
51	    /// Record whether ordinary floating-point multiply/add expressions may
52	    /// contract into fused operations.
53	    pub const fn with_fma_contraction(mut self, enabled: bool) -> Self {
54	        if enabled {
55	            self.0 &= !OPTION_NO_FMA_CONTRACTION;
56	        } else {
57	            self.0 |= OPTION_NO_FMA_CONTRACTION;
58	        }
59	        self
60	    }
61	
62	    /// Whether ordinary floating-point multiply/add expressions may contract.
63	    pub const fn fma_contraction_enabled(self) -> bool {
64	        self.0 & OPTION_NO_FMA_CONTRACTION == 0
65	    }
66	
67	    fn from_bits(bits: u64) -> Result<Self, ArtifactError> {
68	        if bits & !KNOWN_COMPILE_OPTIONS != 0 {
69	            return Err(ArtifactError::UnsupportedCompileOptions(bits));
70	        }
71	        Ok(Self(bits))
72	    }
73	
74	    const fn bits(self) -> u64 {
75	        self.0
76	    }
77	
78	    /// Encode this policy for a sibling `.options` file.
79	    pub const fn sidecar_text(self) -> &'static str {
80	        if self.fma_contraction_enabled() {
81	            COMPILE_OPTIONS_FMA_ON
82	        } else {
83	            COMPILE_OPTIONS_FMA_OFF
84	        }
85	    }
86	
87	    /// Parse a complete version-1 `.options` file.
88	    pub fn from_sidecar_text(value: &str) -> Result<Self, ArtifactError> {
89	        match value {
90	            COMPILE_OPTIONS_FMA_ON => Ok(Self::new()),
91	            COMPILE_OPTIONS_FMA_OFF => Ok(Self::new().with_fma_contraction(false)),
92	            _ => Err(ArtifactError::MalformedCompileOptions(format!(
93	                "expected `{COMPILE_OPTIONS_SIDECAR_HEADER}` with exactly one `fma-contraction=on|off` setting"
94	            ))),
95	        }
96	    }
97	}
98	
99	#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
100	pub enum ArtifactPayloadKind {
101	    Ptx,
102	    NvvmIr,
103	    Ltoir,
104	    Cubin,
105	}
106	
107	impl ArtifactPayloadKind {
108	    pub const fn to_u16(self) -> u16 {
109	        match self {
110	            Self::Ptx => 0x100,
111	            Self::NvvmIr => 0x110,
112	            Self::Ltoir => 0x120,
113	            Self::Cubin => 0x200,
114	        }
115	    }
116	
117	    pub const fn from_u16(value: u16) -> Option<Self> {
118	        match value {
119	            0x100 => Some(Self::Ptx),
120	            0x110 => Some(Self::NvvmIr),
121	            0x120 => Some(Self::Ltoir),
122	            0x200 => Some(Self::Cubin),
123	            _ => None,
124	        }
125	    }
126	}
127	
128	#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
129	pub enum ArtifactEntryKind {
130	    Kernel,
131	    DeviceFunction,
132	}
133	
134	impl ArtifactEntryKind {
135	    pub const fn to_u16(self) -> u16 {
136	        match self {
137	            Self::Kernel => 1,
138	            Self::DeviceFunction => 2,
139	        }
140	    }
141	
142	    pub const fn from_u16(value: u16) -> Option<Self> {
143	        match value {
144	            1 => Some(Self::Kernel),
145	            2 => Some(Self::DeviceFunction),
146	            _ => None,
147	        }
148	    }
149	}
