151	#[derive(Clone, Debug, PartialEq, Eq)]
152	pub struct ArtifactPayloadSpec<'a> {
153	    pub kind: ArtifactPayloadKind,
154	    pub name: &'a str,
155	    pub bytes: &'a [u8],
156	}
157	
