187	pub struct ArtifactBundleSpec<'a> {
188	    pub name: &'a str,
189	    pub target: &'a str,
190	    pub compile_options: ArtifactCompileOptions,
191	    pub payloads: Vec<ArtifactPayloadSpec<'a>>,
192	    pub entries: Vec<ArtifactEntrySpec<'a>>,
193	}
194	
195	impl<'a> ArtifactBundleSpec<'a> {
196	    pub fn new(name: &'a str, target: &'a str) -> Self {
197	        Self {
198	            name,
199	            target,
