207	        self.payloads.push(payload);
208	        self
209	    }
210	
211	    pub fn with_compile_options(mut self, options: ArtifactCompileOptions) -> Self {
212	        self.compile_options = options;
213	        self
214	    }
215	
216	    pub fn with_entry(mut self, entry: ArtifactEntrySpec<'a>) -> Self {
217	        self.entries.push(entry);
218	        self
219	    }
220	}
