661	/// Wrap an artifact blob with a target-specific anchor and a weak legacy alias.
662	///
663	/// New owner-filter-aware macros reference the target-specific symbol. The
664	/// weak package-level alias keeps older macro expansions link-compatible while
665	/// avoiding duplicate-symbol failures when one package has several targets.
666	#[cfg(feature = "object-write")]
667	pub fn build_host_object_for_target_with_legacy_anchor(
668	    section_data: &[u8],
669	    target: &str,
670	    anchor_symbol: &str,
671	    legacy_anchor_symbol: &str,
672	) -> Result<Vec<u8>, ArtifactError> {
673	    if section_data.is_empty() {
674	        return Err(ArtifactError::EmptyPayload);
675	    }
676	    build_host_object_with_section(
677	        ARTIFACT_SECTION_NAME,
678	        section_data,
679	        target,
680	        &[(anchor_symbol, false), (legacy_anchor_symbol, true)],
681	    )
682	}
