844	fn read_slice<'a>(
845	    bytes: &'a [u8],
846	    offset: usize,
847	    len: usize,
848	    field: &'static str,
849	) -> Result<&'a [u8], ArtifactError> {
850	    let end = offset
851	        .checked_add(len)
852	        .ok_or(ArtifactError::TooLarge(field))?;
853	    bytes
854	        .get(offset..end)
855	        .ok_or(ArtifactError::Truncated(field))
856	}
