6	//! FNV-1a 64-bit trace state shared between the CPU oracle and the GPU runs.
7	//!
8	//! The trace is a single `u64` global. Every interesting intermediate value is
9	//! folded into it byte-by-byte. The hash is the program's fingerprint: if both
10	//! backends are correct, the CPU `u64` and the GPU `u64` are equal.
11	//!
12	//! The state starts at zero because cuda-oxide currently only supports
13	//! zero-initialized device statics. Each run must call [`trace_reset`] before
14	//! executing the program, and [`trace_finish`] after.
15	//!
16	//! All trace functions are marked `#[inline]` so their MIR is encoded in the
17	//! `fuzzer` rlib and reachable to cuda-oxide's MIR collector when the smoke
18	//! example is compiled for the device. The `static mut RL_TRACE` already
19	//! prevents the optimizer from constant-folding the trace state away, so we
20	//! don't need `#[inline]` to keep the byte mixers separate.
21	
22	const FNV_OFFSET: u64 = 0xcbf29ce484222325;
23	const FNV_PRIME: u64 = 0x100000001b3;
24	
25	static mut RL_TRACE: u64 = 0;
